+/**
+ * Run an agent until it finishes. A delegate_task call recursively runs the
+ * selected agent, sends its result back as a tool_result, then invokes the
+ * delegating agent again with that result as its next input.
+ */
+async function* runAgentConversation(
+  agentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: string[],
+  isSubAgent: boolean
+): AsyncGenerator<StreamResponse, AgentRunResult> {
+  if (delegationPath.includes(agentId)) {
+    const error = `Circular agent delegation detected: ${[...delegationPath, agentId].join(" -> ")}`;
+    yield { type: "error", error };
+    return { text: "", error };
+  }
+
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+  if (!provider || !agentConfig) {
+    const error = `Agent '${agentId}' not found or provider not available`;
+    // Unknown agents are actionable configuration errors, including when they
+    // are requested from a delegate_task call.
+    yield { type: "error", error };
+    return { text: "", error };
+  }
+
+  const currentPath = [...delegationPath, agentId];
+  let providerRequest: ProviderChatRequest = {
+    message: request.message,
+    sessionId: request.sessionId,
+    requestId: request.requestId,
+    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+  };
+  let accumulatedText = "";
+
+  while (true) {
+    let shouldReinvoke = false;
+    let terminalError: string | undefined;
+
+    for await (const response of provider.executeChat(providerRequest, {
+      debugMode,
+      abortController,
+      temperature: agentConfig.config?.temperature,
+      maxTokens: agentConfig.config?.maxTokens,
+    })) {
+      const chatRoomMessage = createChatRoomMessage(response, agentId);
+      if (chatRoomMessage) {
+        yield {
+          type: "claude_json",
+          data: {
+            type: "chat_room_message",
+            message: chatRoomMessage,
+            session_id: request.sessionId,
+          },
+        };
+      }
+
+      if (response.type === "text") {
+        const text = response.content || "";
+        accumulatedText += text;
+        yield {
+          type: "claude_json",
+          data: { type: "assistant", content: text, model: response.metadata?.model },
+        };
+        continue;
+      }
+
+      if (response.type === "error") {
+        terminalError = response.error || "Agent execution failed";
+        // A delegated agent reports failures solely through its parent's
+        // tool_result. The top-level request retains the existing error event.
+        if (!isSubAgent) yield { type: "error", error: terminalError };
