+      const toolUseId = response.toolUseId || `delegate_${crypto.randomUUID()}`;
+      yield createToolUseMessage(toolUseId, response.toolName, response.toolInput, request.sessionId);
+
+      const input = (response.toolInput && typeof response.toolInput === "object"
+        ? response.toolInput
+        : {}) as DelegateTaskInput;
+      const delegatedAgentId = typeof input.agent_id === "string" ? input.agent_id : "";
+      const instructions = typeof input.instructions === "string" ? input.instructions : "";
+      let delegatedResult: AgentRunResult;
+
+      if (!delegatedAgentId) {
+        delegatedResult = { text: "", error: "delegate_task requires an agent_id" };
+      } else if (currentPath.includes(delegatedAgentId)) {
+        const error = `Circular agent delegation detected: ${[...currentPath, delegatedAgentId].join(" -> ")}`;
+        yield { type: "error", error };
+        delegatedResult = { text: "", error };
+      } else {
+        const delegatedRequest: ChatRequest = { ...request, message: instructions };
+        delegatedResult = yield* runAgentConversation(
+          delegatedAgentId,
+          delegatedRequest,
+          abortController,
+          debugMode,
+          currentPath,
+          true
+        );
+      }
+
+      const toolResultContent = delegatedResult.error
+        ? delegatedResult.error
+        : delegatedResult.text || NO_SUB_AGENT_TEXT;
+      const isError = Boolean(delegatedResult.error);
+      yield createToolResultMessage(toolUseId, toolResultContent, isError, request.sessionId);
+
+      // Re-invoke the delegating agent with an explicit tool_result payload so
+      // every provider sees the same continuation contract.
+      providerRequest = {
+        ...providerRequest,
+        message: JSON.stringify({
+          type: "tool_result",
+          is_error: isError,
+          content: toolResultContent,
+          tool_use_id: toolUseId,
