+/**
+ * Run an agent until it finishes. A delegate_task call recursively runs the
+ * selected agent, sends its result back as a tool_result, then invokes the
+ * delegating agent again with that result as its next input.
+ */
+async function* runAgentConversation(
+  agentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: string[],
+  isSubAgent: boolean
+): AsyncGenerator<StreamResponse, AgentRunResult> {
+  if (delegationPath.includes(agentId)) {
+    const error = `Circular agent delegation detected: ${[...delegationPath, agentId].join(" -> ")}`;
+    yield { type: "error", error };
+    return { text: "", error };
+  }
+
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+  if (!provider || !agentConfig) {
+    const error = `Agent '${agentId}' not found or provider not available`;
+    // Unknown agents are actionable configuration errors, including when they
+    // are requested from a delegate_task call.
+    yield { type: "error", error };
+    return { text: "", error };
+  }
+
+  const currentPath = [...delegationPath, agentId];
+  let providerRequest: ProviderChatRequest = {
+    message: request.message,
+    sessionId: request.sessionId,
+    requestId: request.requestId,
+    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+  };
+  let accumulatedText = "";
+
+  while (true) {
+    let shouldReinvoke = false;
+    let terminalError: string | undefined;
+
+    for await (const response of provider.executeChat(providerRequest, {
+      debugMode,
+      abortController,
+      temperature: agentConfig.config?.temperature,
+      maxTokens: agentConfig.config?.maxTokens,
+    })) {
+      const chatRoomMessage = createChatRoomMessage(response, agentId);
+      if (chatRoomMessage) {
+        yield {
+          type: "claude_json",
+          data: {
+            type: "chat_room_message",
+            message: chatRoomMessage,
+            session_id: request.sessionId,
+          },
+        };
+      }
+
+      if (response.type === "text") {
+        const text = response.content || "";
+        accumulatedText += text;
+        yield {
+          type: "claude_json",
+          data: { type: "assistant", content: text, model: response.metadata?.model },
+        };
+        continue;
+      }
+
+      if (response.type === "error") {
+        terminalError = response.error || "Agent execution failed";
+        // A delegated agent reports failures solely through its parent's
+        // tool_result. The top-level request retains the existing error event.
+        if (!isSubAgent) yield { type: "error", error: terminalError };
+        break;
+      }
+
+      if (response.type !== "tool_use" || response.toolName !== "delegate_task") continue;
+
+      const toolUseId = response.toolUseId || `delegate_${crypto.randomUUID()}`;
+      yield createToolUseMessage(toolUseId, response.toolName, response.toolInput, request.sessionId);
+
+      const input = (response.toolInput && typeof response.toolInput === "object"
+        ? response.toolInput
+        : {}) as DelegateTaskInput;
+      const delegatedAgentId = typeof input.agent_id === "string" ? input.agent_id : "";
+      const instructions = typeof input.instructions === "string" ? input.instructions : "";
+      let delegatedResult: AgentRunResult;
+
+      if (!delegatedAgentId) {
+        delegatedResult = { text: "", error: "delegate_task requires an agent_id" };
+      } else if (currentPath.includes(delegatedAgentId)) {
+        const error = `Circular agent delegation detected: ${[...currentPath, delegatedAgentId].join(" -> ")}`;
+        yield { type: "error", error };
+        delegatedResult = { text: "", error };
+      } else {
+        const delegatedRequest: ChatRequest = { ...request, message: instructions };
+        delegatedResult = yield* runAgentConversation(
+          delegatedAgentId,
+          delegatedRequest,
+          abortController,
+          debugMode,
+          currentPath,
+          true
+        );
+      }
+
+      const toolResultContent = delegatedResult.error
+        ? delegatedResult.error
+        : delegatedResult.text || NO_SUB_AGENT_TEXT;
+      const isError = Boolean(delegatedResult.error);
+      yield createToolResultMessage(toolUseId, toolResultContent, isError, request.sessionId);
+
+      // Re-invoke the delegating agent with an explicit tool_result payload so
+      // every provider sees the same continuation contract.
+      providerRequest = {
+        ...providerRequest,
+        message: JSON.stringify({
+          type: "tool_result",
+          is_error: isError,
+          content: toolResultContent,
+          tool_use_id: toolUseId,
+        }),
+        context: [
+          { role: "user", content: request.message },
+          {
+            role: "assistant",
+            content: JSON.stringify({ type: "tool_use", id: toolUseId, name: "delegate_task", input }),
+          },
+        ],
+      };
+      shouldReinvoke = true;
+      break;
+    }
